class Solution {
    public int addMinimum(String word) {
        int res = 0, i = 0;
        while (i < word.length()) {
            if (i + 2 < word.length() && word.charAt(i) == 'a' && word.charAt(i + 1) == 'b' && word.charAt(i + 2) == 'c') {
                i += 3;
            } else {
                res++;
                i++;
            }
        }
        res += (2 - word.length() % 3) % 3;
        return res;
    }
}
